export type Cell = [x: number, y: number];

const cellKey = ([x, y]: Cell): string => `${x},${y}`;

const neighborsOf = ([x, y]: Cell): Cell[] => {
  const offsets = [-1, 0, 1];
  const result: Cell[] = [];
  for (const dx of offsets) {
    for (const dy of offsets) {
      if (dx === 0 && dy === 0) continue;
      result.push([x + dx, y + dy]);
    }
  }
  return result;
};

const countLiveNeighbors = (cells: Cell[]): Map<string, { cell: Cell; count: number }> => {
  const counts = new Map<string, { cell: Cell; count: number }>();
  for (const cell of cells) {
    for (const neighbor of neighborsOf(cell)) {
      const key = cellKey(neighbor);
      const existing = counts.get(key);
      if (existing) existing.count += 1;
      else counts.set(key, { cell: neighbor, count: 1 });
    }
  }
  return counts;
};

const survives = (count: number): boolean => count === 2 || count === 3;
const isBorn = (count: number): boolean => count === 3;

export function nextGeneration(cells: Cell[]): Cell[] {
  const liveKeys = new Set(cells.map(cellKey));
  const neighborCounts = countLiveNeighbors(cells);

  const nextGen: Cell[] = [];
  for (const [key, { cell, count }] of neighborCounts) {
    const wasAlive = liveKeys.has(key);
    if (wasAlive ? survives(count) : isBorn(count)) {
      nextGen.push(cell);
    }
  }
  return nextGen;
}
